import React, { useState, useCallback } from 'react';
import { FileUp, FileText, Download, Copy, Check, Trash2, ExternalLink, Library } from 'lucide-react';
import { AppState, ExtractionResult } from './types';
import { extractDoisFromPdf } from './services/geminiService';
import { Button } from './components/Button';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [result, setResult] = useState<ExtractionResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      setError("Please upload a valid PDF file.");
      return;
    }

    setAppState(AppState.EXTRACTING);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        try {
          const data = await extractDoisFromPdf(base64);
          setResult(data);
          setAppState(AppState.SUCCESS);
        } catch (err: any) {
          setError(err.message || "Failed to extract DOIs.");
          setAppState(AppState.ERROR);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Error reading file.");
      setAppState(AppState.ERROR);
    }
  };

  const copyToClipboard = () => {
    if (!result?.dois.length) return;
    navigator.clipboard.writeText(result.dois.join('\n'));
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const reset = () => {
    setAppState(AppState.IDLE);
    setResult(null);
    setError(null);
  };

  const generateSciDownlCommand = () => {
    if (!result?.dois.length) return "";
    return `scidownl download --doi ${result.dois.join(' ')} --out ./downloads`;
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      {/* Header */}
      <header className="mb-12 text-center">
        <div className="inline-flex items-center justify-center p-3 bg-blue-100 text-blue-600 rounded-2xl mb-4">
          <Library size={32} />
        </div>
        <h1 className="text-4xl font-bold text-slate-900 tracking-tight mb-3">
          DOI Extractor <span className="text-blue-600">& Assistant</span>
        </h1>
        <p className="text-slate-500 text-lg max-w-xl mx-auto">
          Upload an academic paper to extract all reference DOIs using AI. 
          Prepare your list for batch downloading with SciDownl.
        </p>
      </header>

      <main>
        {appState === AppState.IDLE && (
          <div className="border-2 border-dashed border-slate-200 rounded-3xl p-12 bg-white flex flex-col items-center transition-all hover:border-blue-400 hover:bg-blue-50/30">
            <div className="w-16 h-16 bg-blue-50 text-blue-500 rounded-full flex items-center justify-center mb-6">
              <FileUp size={32} />
            </div>
            <h3 className="text-xl font-semibold mb-2 text-slate-800">Upload Academic PDF</h3>
            <p className="text-slate-500 text-center mb-8 max-w-sm">
              Drag and drop your PDF here or click to browse. We'll analyze the references for you.
            </p>
            <input
              type="file"
              id="file-upload"
              className="hidden"
              accept=".pdf"
              onChange={handleFileUpload}
            />
            <label htmlFor="file-upload">
              <Button variant="primary" className="cursor-pointer" as="span">
                Select PDF File
              </Button>
            </label>
          </div>
        )}

        {appState === AppState.EXTRACTING && (
          <div className="bg-white rounded-3xl p-12 shadow-sm text-center border border-slate-100">
            <div className="relative w-20 h-20 mx-auto mb-6">
              <div className="absolute inset-0 border-4 border-blue-100 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-blue-600 rounded-full border-t-transparent animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center text-blue-600">
                <FileText size={32} />
              </div>
            </div>
            <h3 className="text-2xl font-bold text-slate-800 mb-2">Analyzing PDF References</h3>
            <p className="text-slate-500 animate-pulse">Gemini 3 Pro is extracting DOI numbers...</p>
          </div>
        )}

        {appState === AppState.ERROR && (
          <div className="bg-red-50 border border-red-100 rounded-3xl p-8 text-center">
            <div className="text-red-500 mb-4 inline-block">
              <Trash2 size={48} />
            </div>
            <h3 className="text-xl font-bold text-red-800 mb-2">Extraction Failed</h3>
            <p className="text-red-600 mb-6">{error}</p>
            <Button variant="secondary" onClick={reset}>Try Another File</Button>
          </div>
        )}

        {appState === AppState.SUCCESS && result && (
          <div className="space-y-6">
            <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
              <div className="p-6 bg-slate-50 border-b border-slate-100 flex items-center justify-between">
                <div>
                  <h2 className="text-xl font-bold text-slate-800">Extraction Results</h2>
                  <p className="text-sm text-slate-500 mt-1">
                    {result.dois.length} DOI numbers found in {result.paperTitle || "the document"}
                  </p>
                </div>
                <div className="flex gap-2">
                   <Button variant="ghost" onClick={reset} title="Start Over">
                    <Trash2 size={18} />
                   </Button>
                </div>
              </div>

              <div className="p-6">
                <div className="flex flex-col md:flex-row gap-4 mb-8">
                  <div className="flex-1">
                    <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-2">Batch Commands</h4>
                    <div className="bg-slate-900 text-slate-300 p-4 rounded-xl font-mono text-sm overflow-x-auto relative group">
                      <code>{generateSciDownlCommand()}</code>
                      <button 
                        onClick={() => {
                          navigator.clipboard.writeText(generateSciDownlCommand());
                          setCopied(true);
                          setTimeout(() => setCopied(false), 2000);
                        }}
                        className="absolute right-2 top-2 p-2 bg-white/10 hover:bg-white/20 rounded-lg text-white opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        {copied ? <Check size={16} /> : <Copy size={16} />}
                      </button>
                    </div>
                  </div>
                </div>

                <h4 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-4">DOI List</h4>
                <div className="space-y-2 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                  {result.dois.map((doi, idx) => (
                    <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl hover:bg-slate-100 transition-colors">
                      <span className="text-sm font-medium text-slate-700 truncate mr-4">{doi}</span>
                      <div className="flex items-center gap-2">
                        <a 
                          href={`https://doi.org/${doi}`} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                          title="Open on DOI.org"
                        >
                          <ExternalLink size={16} />
                        </a>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="p-6 bg-slate-50 border-t border-slate-100 flex flex-wrap gap-3">
                <Button onClick={copyToClipboard} variant="primary">
                  {copied ? <Check size={18} /> : <Copy size={18} />}
                  {copied ? 'Copied' : 'Copy All DOIs'}
                </Button>
                <Button variant="secondary" onClick={() => {
                   const blob = new Blob([result.dois.join('\n')], { type: 'text/plain' });
                   const url = URL.createObjectURL(blob);
                   const a = document.createElement('a');
                   a.href = url;
                   a.download = 'dois_list.txt';
                   a.click();
                }}>
                  <Download size={18} />
                  Download .txt
                </Button>
              </div>
            </div>

            <div className="bg-blue-600 text-white rounded-3xl p-8 shadow-xl shadow-blue-200">
              <h3 className="text-xl font-bold mb-3 flex items-center gap-2">
                <Download size={24} />
                Next Steps for Downloading
              </h3>
              <p className="mb-6 opacity-90 leading-relaxed">
                Since paper downloading often requires specific tools or institutional access, 
                we've prepared the DOI list for you. Use the command above with the 
                <a href="https://github.com/Tishacy/SciDownl" target="_blank" className="underline ml-1 font-medium">SciDownl script</a>
                to batch download the full papers to your computer.
              </p>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="bg-white/10 p-4 rounded-2xl">
                  <span className="block text-sm font-bold uppercase mb-1 opacity-70">Step 1</span>
                  <p className="text-sm">Copy the list of extracted DOIs or the generated CLI command.</p>
                </div>
                <div className="bg-white/10 p-4 rounded-2xl">
                  <span className="block text-sm font-bold uppercase mb-1 opacity-70">Step 2</span>
                  <p className="text-sm">Run the command in your terminal to start the batch download process.</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="mt-20 pt-8 border-t border-slate-200 text-center text-slate-400 text-sm">
        <p>© {new Date().getFullYear()} Academic Resource Assistant. Powered by Gemini 3 Pro.</p>
      </footer>
    </div>
  );
};

export default App;

