export interface ReferenceItem {
  title: string;
  doi: string;
}

export interface ExtractionResult {
  paperTitle?: string;
  references: ReferenceItem[];
  skippedCount: number;
}

export enum AppState {
  IDLE = 'IDLE',
  EXTRACTING = 'EXTRACTING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExtractionResult } from "../types";

export const extractDoisFromPdf = async (base64Pdf: string): Promise<ExtractionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze this academic PDF file. 
    1. Identify the main title of the paper.
    2. Go to the "References" or "Bibliography" section.
    3. For each reference:
       - Extract the full title of the cited article/paper.
       - Extract the DOI (Digital Object Identifier) if present.
       - If a reference does NOT have a DOI, skip it but keep track of how many you skipped.
    4. Return a JSON object with:
       - "paperTitle": The title of the uploaded PDF.
       - "references": An array of objects each containing "title" and "doi".
       - "skippedCount": The total number of references found that did not have a DOI.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Pdf, mimeType: 'application/pdf' } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            paperTitle: { type: Type.STRING },
            references: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  doi: { type: Type.STRING }
                },
                required: ["title", "doi"]
              }
            },
            skippedCount: { type: Type.INTEGER }
          },
          required: ["references", "skippedCount"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Empty response from AI");

    return JSON.parse(text) as ExtractionResult;
  } catch (error) {
    console.error("Gemini Extraction Error:", error);
    throw error;
  }
};

