                          <Button variant="ghost" className="w-full py-4 px-5 rounded-2xl text-slate-400 hover:text-indigo-600 hover:bg-indigo-50" title="Open official DOI.org page">
                            <ExternalLink size={20} />
                          </Button>
                        </a>
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="bg-white py-20 rounded-[2.5rem] border border-slate-100 text-center flex flex-col items-center">
                  <div className="bg-slate-50 p-6 rounded-full mb-4 text-slate-300">
                    <Library size={48} />
                  </div>
                  <h3 className="text-xl font-bold text-slate-700">No DOIs Detected</h3>
                  <p className="text-slate-400 max-w-xs mx-auto mt-2">
                    We scanned the bibliography but couldn't find any references with DOI numbers.
                  </p>
                  <Button variant="secondary" className="mt-8" onClick={reset}>Try Another PDF</Button>
                </div>
              )}
            </div>

            {/* Bulk Download Info */}
            {result.references.length > 0 && (
              <div className="bg-indigo-900 text-white rounded-[2.5rem] p-10 shadow-2xl shadow-indigo-200 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition-transform">
                  <Zap size={120} />
                </div>
                <div className="relative z-10">
                  <h3 className="text-2xl font-bold mb-4 flex items-center gap-3">
                    <Layers size={28} />
                    Batch Actions & Bulk Download
                  </h3>
                  <p className="mb-8 text-indigo-100 max-w-2xl leading-relaxed text-lg">
                    Process all extracted references at once. You can open all links in tabs or download a portable research binder for later.
                  </p>
                  <div className="flex flex-wrap gap-4">
                    <Button 
                      variant="primary" 
                      className="bg-white text-indigo-900 hover:bg-indigo-50 border-none px-8 py-4 rounded-2xl font-bold shadow-xl"
                      onClick={openAllLinks}
                    >
                      <OpenIcon size={20} />
                      Open All Links (${result.references.length})
                    </Button>
                    <Button 
                      variant="secondary" 
                      className="bg-indigo-800 text-white border-indigo-700 hover:bg-indigo-700 px-8 py-4 rounded-2xl font-bold"
                      onClick={downloadHtmlBinder}
                    >
                      <Download size={20} />
                      Download HTML Binder
                    </Button>
                    <Button 
                      variant="ghost" 
                      className="text-indigo-200 hover:bg-white/10 px-8 py-4 rounded-2xl"
                      onClick={() => {
                        const blob = new Blob([result.references.map(r => `${r.title}\nDOI: ${r.doi}\nDownload: ${getSciHubLink(r.doi)}\n`).join('\n---\n\n')], { type: 'text/plain' });
                        const url = URL.createObjectURL(blob);
                        const a = document.createElement('a');
                        a.href = url;
                        a.download = 'reading_list.txt';
                        a.click();
                      }}
                    >
                      <FileText size={20} />
                      Export Text List
                    </Button>
                  </div>
                  <p className="mt-6 text-xs text-indigo-300 italic">
                    Note: "Open All" might be blocked by your browser's pop-up blocker.
                  </p>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <footer className="mt-20 pt-10 border-t border-slate-200 text-center text-slate-400 text-sm font-medium">
        <p>Advanced PDF Reference Analysis powered by Google Gemini 3 Pro.</p>
        <p className="mt-1">Direct download links are powered by Sci-Hub mirrors (sci-hub.ist).</p>
      </footer>
    </div>
  );
};

export default App;
